mapper.select:
SELECT f.faq_no AS faqNo, f.cs_cate_no AS csCateNo, f.writer_no AS writerNo, f.title, f.content, f.hit, f.reg_date AS regDate, f.update_date AS updateDate, c.cate_name AS cateName, p.cate_name AS parentCateName
FROM faq f JOIN cs_category c ON f.cs_cate_no = c.cs_cate_no LEFT JOIN cs_category p ON c.parent_no = p.cs_cate_no
WHERE f.faq_no = #{faqNo}
